export { $lib } from "./lib.js";

/**
 * Emitter name used for generating "Code generated by X. DO NOT EDIT." header.
 * Other emitters import this to include the header in generated files.
 */
export const generatedHeader = "Code generated by @qninhdt/typespec-orm. DO NOT EDIT.";

/**
 * Compose a generated-file banner. Returns the canonical
 * `generatedHeader` marker by default; pass `extra` to prepend a license,
 * ticket link, or any service-specific preamble. The canonical marker is
 * always present so downstream tools can still detect generated files.
 */
export function buildGeneratedHeader(extra?: string): string {
  const trimmed = extra?.trim();
  if (!trimmed) return generatedHeader;
  return `${trimmed}\n${generatedHeader}`;
}
